function minOperations(A) {
    if (A.length <= 1) return 0;

    // Helper function to calculate cost for a target sequence starting with specified parity
    // startParity: 0 for Even, 1 for Odd
    const calculateCost = (arr, startParity) => {
        let cost = 0;
        for (let i = 0; i < arr.length; i++) {
            // Required parity at index i
            const requiredParity = (startParity + i) % 2;

            // Current parity of arr[i]
            const currentParity = arr[i] % 2;

            if (currentParity !== requiredParity) {
                cost++;
            }
        }
        return cost;
    };

    // Case 1: Target sequence starts with Even (0, 1, 0, 1, ...)
    const costEvenStart = calculateCost(A, 0);

    // Case 2: Target sequence starts with Odd (1, 0, 1, 0, ...)
    const costOddStart = calculateCost(A, 1);

    return Math.min(costEvenStart, costOddStart);
}

