    for (const op of operations) {
        const [L, R, V] = op;
        const L0 = L - 1; // 0-indexed start
        const R0 = R - 1; // 0-indexed end

        // K is the effective magnitude added to even indices relative to the start.
        // K = V * (-1)^L0
        const K = (L0 % 2 === 0) ? V : -V;

        // The overall addition is K * (-1)^i

        // 1. Even indices (i is even, (-1)^i = 1. Contribution: K)
        diff_even[L0] += K;
        if (R0 + 1 <= n) {
            diff_even[R0 + 1] -= K;
        }

        // 2. Odd indices (i is odd, (-1)^i = -1. Contribution: -K)
        diff_odd[L0] += -K;
        if (R0 + 1 <= n) {
            diff_odd[R0 + 1] -= -K; // i.e., += K
        }
    }

    let result = new Array(n).fill(0);
    let current_sum_even = 0;
    let current_sum_odd = 0;

    for (let i = 0; i < n; i++) {
        current_sum_even += diff_even[i];
        current_sum_odd += diff_odd[i];

        if (i % 2 === 0) { // Even index
            result[i] = current_sum_even;
        } else { // Odd index
            result[i] = current_sum_odd;
        }
    }

    return result;
