    public int[] zigzagRangeIncrement(int n, int[][] operations) {
        long[] diffEven = new long[n + 1];
        long[] diffOdd = new long[n + 1];

        for (int[] op : operations) {
            int L = op[0];
            int R = op[1];
            int V = op[2];

            int L0 = L - 1; 
            int R0 = R - 1; 

            long K = (L0 % 2 == 0) ? V : -V;

            // Update for Even indices (i even -> add K)
            diffEven[L0] += K;
            if (R0 + 1 <= n) {
                diffEven[R0 + 1] -= K;
            }

            // Update for Odd indices (i odd -> add -K)
            diffOdd[L0] += -K;
            if (R0 + 1 <= n) {
                diffOdd[R0 + 1] += K;
            }
        }

        int[] result = new int[n];
        long currentSumEven = 0;
        long currentSumOdd = 0;

