function max_value_double_constraint(N, C, T, W, A, V) {
    // dp[w][a] = max value for weight w and attribute sum a
    // Size (C+1) x (T+1). Initialize with -1 (unreachable) except dp[0][0] = 0.
    const dp = Array(C + 1).fill(0).map(() => Array(T + 1).fill(-1));
    dp[0][0] = 0;

    for (let i = 0; i < N; i++) {
        const w = W[i];
        const a = A[i];
        const v = V[i];

        for (let current_w = C; current_w >= w; current_w--) {
            for (let current_a = T; current_a >= a; current_a--) {
                if (dp[current_w - w][current_a - a] !== -1) {
                    dp[current_w][current_a] = Math.max(
                        dp[current_w][current_a],
                        dp[current_w - w][current_a - a] + v
                    );
                }
            }
        }
    }

    // Find the maximum value achieved with exactly attribute sum T across all possible weights <= C
    let max_val = -1;
    for (let current_w = 0; current_w <= C; current_w++) {
        max_val = Math.max(max_val, dp[current_w][T]);
    }

    return max_val;
